// And groups predicates with the AND operator between them.
func And(predicates ...predicate.TagValue) predicate.TagValue {
	return predicate.TagValue(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.TagValue) predicate.TagValue {
	return predicate.TagValue(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.TagValue) predicate.TagValue {
	return predicate.TagValue(sql.NotPredicates(p))
}
